-- =============================================================================
-- CMS Synthetic Medicare Claims DWH
-- Script  : 04_staging_beneficiary.sql
-- Purpose : Transform raw.beneficiary_* -> staging.beneficiary
-- Run as  : postgres on database cms_medicare
-- =============================================================================
-- Design decisions:
--   D6:  One staging table for all 11 years (not 11 separate tables)
--        Year is a column, not part of the table name.
--   D11: Monthly arrays (156 columns) kept as-is in staging.
--        Aggregation to annual snapshot happens in mart (fact_enrollment).
--   D4:  Column names lowercased, matching CMS codebook names exactly.
--        No abbreviation expansion — keeps machine-readable vs codebook.
-- =============================================================================


-- ---------------------------------------------------------------------------
-- Drop and create staging.beneficiary
-- ---------------------------------------------------------------------------

DROP TABLE IF EXISTS staging.beneficiary;
CREATE TABLE staging.beneficiary (

    -- Source year (added to distinguish annual snapshots)
    enrollmt_ref_yr              SMALLINT,

    -- Identifiers
    bene_id                      TEXT,        -- negative number = synthetic marker

    -- Geography (TEXT: leading zeros in state/county/zip are significant)
    state_code                   TEXT,
    county_cd                    TEXT,
    zip_cd                       TEXT,

    -- Demographics
    bene_birth_dt                DATE,
    bene_death_dt                DATE,
    valid_death_dt_sw            TEXT,
    sex_ident_cd                 TEXT,
    bene_race_cd                 TEXT,
    rti_race_cd                  TEXT,
    age_at_end_ref_yr            SMALLINT,

    -- Eligibility
    esrd_ind                     TEXT,
    entlmt_rsn_orig              TEXT,
    entlmt_rsn_curr              TEXT,
    bene_pta_trmntn_cd           TEXT,
    bene_ptb_trmntn_cd           TEXT,
    crnt_bic_cd                  TEXT,
    covstart                     DATE,

    -- Enrollment source / sample flags
    enrl_src                     TEXT,
    sample_group                 TEXT,
    enhanced_five_percent_flag   TEXT,

    -- Coverage totals (months)
    bene_hi_cvrage_tot_mons      SMALLINT,
    bene_smi_cvrage_tot_mons     SMALLINT,
    bene_state_buyin_tot_mons    SMALLINT,
    bene_hmo_cvrage_tot_mons     SMALLINT,
    rds_cvrg_mons                SMALLINT,
    dual_elgbl_mons              SMALLINT,
    ptd_plan_cvrg_mons           SMALLINT,

    -- Monthly arrays: Medicare status (01-12)
    mdcr_status_code_01 TEXT, mdcr_status_code_02 TEXT, mdcr_status_code_03 TEXT,
    mdcr_status_code_04 TEXT, mdcr_status_code_05 TEXT, mdcr_status_code_06 TEXT,
    mdcr_status_code_07 TEXT, mdcr_status_code_08 TEXT, mdcr_status_code_09 TEXT,
    mdcr_status_code_10 TEXT, mdcr_status_code_11 TEXT, mdcr_status_code_12 TEXT,

    -- Monthly arrays: Medicare entitlement/buyin (01-12)
    mdcr_entlmt_buyin_ind_01 TEXT, mdcr_entlmt_buyin_ind_02 TEXT,
    mdcr_entlmt_buyin_ind_03 TEXT, mdcr_entlmt_buyin_ind_04 TEXT,
    mdcr_entlmt_buyin_ind_05 TEXT, mdcr_entlmt_buyin_ind_06 TEXT,
    mdcr_entlmt_buyin_ind_07 TEXT, mdcr_entlmt_buyin_ind_08 TEXT,
    mdcr_entlmt_buyin_ind_09 TEXT, mdcr_entlmt_buyin_ind_10 TEXT,
    mdcr_entlmt_buyin_ind_11 TEXT, mdcr_entlmt_buyin_ind_12 TEXT,

    -- Monthly arrays: HMO indicator (01-12)
    hmo_ind_01 TEXT, hmo_ind_02 TEXT, hmo_ind_03 TEXT, hmo_ind_04 TEXT,
    hmo_ind_05 TEXT, hmo_ind_06 TEXT, hmo_ind_07 TEXT, hmo_ind_08 TEXT,
    hmo_ind_09 TEXT, hmo_ind_10 TEXT, hmo_ind_11 TEXT, hmo_ind_12 TEXT,

    -- Monthly arrays: Part C contract (01-12)
    ptc_cntrct_id_01 TEXT, ptc_cntrct_id_02 TEXT, ptc_cntrct_id_03 TEXT,
    ptc_cntrct_id_04 TEXT, ptc_cntrct_id_05 TEXT, ptc_cntrct_id_06 TEXT,
    ptc_cntrct_id_07 TEXT, ptc_cntrct_id_08 TEXT, ptc_cntrct_id_09 TEXT,
    ptc_cntrct_id_10 TEXT, ptc_cntrct_id_11 TEXT, ptc_cntrct_id_12 TEXT,

    -- Monthly arrays: Part C PBP ID (01-12)
    ptc_pbp_id_01 TEXT, ptc_pbp_id_02 TEXT, ptc_pbp_id_03 TEXT,
    ptc_pbp_id_04 TEXT, ptc_pbp_id_05 TEXT, ptc_pbp_id_06 TEXT,
    ptc_pbp_id_07 TEXT, ptc_pbp_id_08 TEXT, ptc_pbp_id_09 TEXT,
    ptc_pbp_id_10 TEXT, ptc_pbp_id_11 TEXT, ptc_pbp_id_12 TEXT,

    -- Monthly arrays: Part C plan type (01-12)
    ptc_plan_type_cd_01 TEXT, ptc_plan_type_cd_02 TEXT, ptc_plan_type_cd_03 TEXT,
    ptc_plan_type_cd_04 TEXT, ptc_plan_type_cd_05 TEXT, ptc_plan_type_cd_06 TEXT,
    ptc_plan_type_cd_07 TEXT, ptc_plan_type_cd_08 TEXT, ptc_plan_type_cd_09 TEXT,
    ptc_plan_type_cd_10 TEXT, ptc_plan_type_cd_11 TEXT, ptc_plan_type_cd_12 TEXT,

    -- Monthly arrays: Part D contract (01-12)
    ptd_cntrct_id_01 TEXT, ptd_cntrct_id_02 TEXT, ptd_cntrct_id_03 TEXT,
    ptd_cntrct_id_04 TEXT, ptd_cntrct_id_05 TEXT, ptd_cntrct_id_06 TEXT,
    ptd_cntrct_id_07 TEXT, ptd_cntrct_id_08 TEXT, ptd_cntrct_id_09 TEXT,
    ptd_cntrct_id_10 TEXT, ptd_cntrct_id_11 TEXT, ptd_cntrct_id_12 TEXT,

    -- Monthly arrays: Part D PBP ID (01-12)
    ptd_pbp_id_01 TEXT, ptd_pbp_id_02 TEXT, ptd_pbp_id_03 TEXT,
    ptd_pbp_id_04 TEXT, ptd_pbp_id_05 TEXT, ptd_pbp_id_06 TEXT,
    ptd_pbp_id_07 TEXT, ptd_pbp_id_08 TEXT, ptd_pbp_id_09 TEXT,
    ptd_pbp_id_10 TEXT, ptd_pbp_id_11 TEXT, ptd_pbp_id_12 TEXT,

    -- Monthly arrays: Part D segment ID (01-12)
    ptd_sgmt_id_01 TEXT, ptd_sgmt_id_02 TEXT, ptd_sgmt_id_03 TEXT,
    ptd_sgmt_id_04 TEXT, ptd_sgmt_id_05 TEXT, ptd_sgmt_id_06 TEXT,
    ptd_sgmt_id_07 TEXT, ptd_sgmt_id_08 TEXT, ptd_sgmt_id_09 TEXT,
    ptd_sgmt_id_10 TEXT, ptd_sgmt_id_11 TEXT, ptd_sgmt_id_12 TEXT,

    -- Monthly arrays: RDS indicator (01-12)
    rds_ind_01 TEXT, rds_ind_02 TEXT, rds_ind_03 TEXT, rds_ind_04 TEXT,
    rds_ind_05 TEXT, rds_ind_06 TEXT, rds_ind_07 TEXT, rds_ind_08 TEXT,
    rds_ind_09 TEXT, rds_ind_10 TEXT, rds_ind_11 TEXT, rds_ind_12 TEXT,

    -- Monthly arrays: Dual eligibility status (01-12)
    dual_stus_cd_01 TEXT, dual_stus_cd_02 TEXT, dual_stus_cd_03 TEXT,
    dual_stus_cd_04 TEXT, dual_stus_cd_05 TEXT, dual_stus_cd_06 TEXT,
    dual_stus_cd_07 TEXT, dual_stus_cd_08 TEXT, dual_stus_cd_09 TEXT,
    dual_stus_cd_10 TEXT, dual_stus_cd_11 TEXT, dual_stus_cd_12 TEXT,

    -- Monthly arrays: Cost sharing group (01-12)
    cst_shr_grp_cd_01 TEXT, cst_shr_grp_cd_02 TEXT, cst_shr_grp_cd_03 TEXT,
    cst_shr_grp_cd_04 TEXT, cst_shr_grp_cd_05 TEXT, cst_shr_grp_cd_06 TEXT,
    cst_shr_grp_cd_07 TEXT, cst_shr_grp_cd_08 TEXT, cst_shr_grp_cd_09 TEXT,
    cst_shr_grp_cd_10 TEXT, cst_shr_grp_cd_11 TEXT, cst_shr_grp_cd_12 TEXT,

    -- Monthly arrays: State/county FIPS (01-12)
    state_cnty_fips_cd_01 TEXT, state_cnty_fips_cd_02 TEXT,
    state_cnty_fips_cd_03 TEXT, state_cnty_fips_cd_04 TEXT,
    state_cnty_fips_cd_05 TEXT, state_cnty_fips_cd_06 TEXT,
    state_cnty_fips_cd_07 TEXT, state_cnty_fips_cd_08 TEXT,
    state_cnty_fips_cd_09 TEXT, state_cnty_fips_cd_10 TEXT,
    state_cnty_fips_cd_11 TEXT, state_cnty_fips_cd_12 TEXT,

    -- Audit
    dwh_load_date                TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE staging.beneficiary IS
    'Typed beneficiary data, all 11 years unioned. '
    'Monthly arrays kept as-is; aggregation to annual snapshot in mart.fact_enrollment.';


-- ---------------------------------------------------------------------------
-- Load: INSERT from all 11 raw tables
-- One INSERT per year for clarity and easy re-run of individual years
-- ---------------------------------------------------------------------------

-- Helper macro (repeated 11 times — one per year)
-- Pattern: cast scalars, keep monthly arrays as clean_text

