-- ---------------------------------------------------------------------------
-- Verification
-- ---------------------------------------------------------------------------

SELECT
    enrollmt_ref_yr,
    COUNT(*)        AS rows,
    COUNT(DISTINCT bene_id) AS unique_bene,
    COUNT(*) FILTER (WHERE bene_birth_dt IS NULL) AS null_birth_dt,
    COUNT(*) FILTER (WHERE age_at_end_ref_yr IS NULL) AS null_age
FROM staging.beneficiary
GROUP BY enrollmt_ref_yr
ORDER BY enrollmt_ref_yr;
